import re
from datetime import datetime, timedelta

def audit_freshness(retrieved_nodes, max_age_days=30):
    now = datetime.now()
    stale_docs = []

    for node in retrieved_nodes:
        # Extract date from metadata or content
        date_match = re.search(r'\d{4}-\d{2}-\d{2}', node.text)
        if date_match:
            doc_date = datetime.strptime(date_match.group(), '%Y-%m-%d')
            if now - doc_date > timedelta(days=max_age_days):
                stale_docs.append((node, doc_date))

    if stale_docs:
        print(f'⚠️ {len(stale_docs)} stale documents found')
        for node, date in stale_docs:
            print(f'  - {date.strftime("%Y-%m-%d")}: {node.text[:100]}...')

    return len(stale_docs) == 0

# Usage
audit_freshness(retrieved_nodes)

